Action.Str:
FILE=$(find /storage/emulated/0/Tasker/Mushrooms -name "*.gpx" | xargs ls -t 2>/dev/null | head -n 1)

[ -z "$FILE" ] && exit 0

COUNT=$(grep -o "<wpt " "$FILE" | wc -l)

if [ "$COUNT" -le 1 ]; then
  rm "$FILE"
else
  awk '
    /<wpt / { in_wpt=1; wpt_buf=""; }
    in_wpt { wpt_buf = wpt_buf $0 "\n"; }
    /<\/wpt>/ { in_wpt=0; blocks[++n] = wpt_buf; wpt_buf=""; next; }
    !in_wpt && !/^$/ { lines[++lc] = $0; }
    END {
      for (i=1; i<=lc; i++) {
        if (lines[i] ~ /<\/gpx>/) continue;
        print lines[i];
      }
      for (i=1; i<n; i++) printf "%s", blocks[i];
      print "</gpx>";
    }
  ' "$FILE" > "$FILE.tmp" && mv "$FILE.tmp" "$FILE"
fi
